class AutonomousAIVaults:
    def compute_rl_reward(self, portfolio_return: float, max_drawdown: float, sharpe: float) -> float:
        """Reinforcement Learning ajanı için ödül/ceza fonksiyonu."""
        return (portfolio_return * 10.0) + (sharpe * 5.0) - (max_drawdown * 20.0)

